select @date_to as date_to, @so_ky as so_ky
exec rs_rptReceivableAgingReportByInvoice @date_to, @date, @ma_dvcs, @tk, @ma_kh, @nh_kh1, @nh_kh2, @nh_kh3, @so_ky, @so_du, @in_hd, @nhom, @@language, @@userID, @@admin
&DynamicFieldFilterPara;
