      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  if (!f.getItemValue('date') {f.setItemValue('date', new Date());}
  f.live(f.getItem('date'));
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, d2 = f.getItem('date_to').value, x = f.getItemValue('mau_bc'), type = (f.getItemValue('nhom') == '0');
      g._days = f.getItemValue('so_ky');
      g._alterTitle = [null, [['%d2', d2, true]]];
      g._hiddenFields = [
        {Fields: 'ma_nt, t_tt_nt0, t_tt_nt1, du_cuoi_nt, so_du_nt0, so_du_nt1, so_du_nt2, so_du_nt3, so_du_nt4', Value: (x == '10')},
        {Fields: 't_tt0, t_tt1, du_cuoi, so_du0, so_du1, so_du2, so_du3, so_du4', Value: (x == '20')},
        {Fields: 'ma_hd, ten_hd_ex', Value: type)}
      ];
      if (g._fields.length > 0) try {init$GridReport$(g);} catch (ex) {}
      g._hiddenForms = [
        {Form: [2, 3, 8, 7], Value: type},
        {Form: [0, 1, 6, 5], Value: !type}
      ];
      if (!g._v) g._v = g._days;
      if (g._v != g._days) {
        remove$GridReport$Filter(g);
        g._v = g._days;
      }
      break;
    default:
      break;
  }
}
function remove$GridReport$Filter(g) {
  var r = ('so_du1, so_du2, so_du3, so_du4, so_du_nt1, so_du_nt2, so_du_nt3, so_du_nt4').split(','), name, field;
  for (i = 0; i < r.length; i++) {
    for (var j = 0; j < g._filter.length; j++) {
      name = $func.trim(r[i]);
      field = $func.findField(name, g._fields)
      if (field) field.FilterPanelValue = '';
      if (g._filter[j].match(/^(\w+):/)[1] == name) {
        Array.removeAt(g._filter, j);
        break;
      }
    }
  }
}
/* </flatten> */



